import styled from 'styled-components'

import { CartItem } from '../../app-state/cart'
import { toCurrency } from '../../helpers'
import { Button } from '../Button'
import { Select } from '../forms/Select'
import { Sidebar } from '../Sidebar'
import { Body } from '../typography'

const FooterContainer = styled.div`
  display: flex;
  flex-direction: column;
  width: 100%;
  justify-content: space-between;
`

const TotalSection = styled.div`
  display: flex;
  justify-content: space-between;
  margin-bottom: 24px;
`

const Footer = ({ onClick, totalPrice }: any) => (
  <FooterContainer>
    <TotalSection>
      <Body type="span">Total</Body>
      <Body type="span">{toCurrency(totalPrice)}</Body>
    </TotalSection>
    <Button disabled={totalPrice === 0} large onClick={onClick}>
      Checkout
    </Button>
  </FooterContainer>
)

const MenuItemContainer = styled.div`
  display: flex;
  align-items: flex-start;
  > div:first-of-type {
    padding-right: 1rem;
    flex: 0.75;
  }

  > div:last-of-type {
    flex: 0.25;
  }
`

const ShoppingCartMenuItem = ({ item, onChange }: any) => (
  <MenuItemContainer>
    <div>
      <Body type="span" fontWeight="medium">
        {item.name}
      </Body>
      <Body>{item.description}</Body>
      <Body>{toCurrency(item.price * item.quantity)}</Body>
    </div>
    <Select
      value={item.quantity}
      onChange={onChange}
      aria-label={`${item.quantity} times`}
      options={[...Array.from({ length: 11 }).keys()]}
    />
  </MenuItemContainer>
)

type ShoppingCartMenuProps = {
  isOpen: boolean
  totalPrice: number
  onClose: () => void
  cartItems: CartItem[]
  onGoToCheckoutClick?: () => void
  onItemChange: (item: any) => void
}

export const ShoppingCartMenu = ({
  isOpen,
  onClose,
  cartItems,
  totalPrice,
  onItemChange,
  onGoToCheckoutClick,
}: ShoppingCartMenuProps) => (
  <Sidebar
    title="Your order"
    onClose={onClose}
    isOpen={isOpen}
    footer={<Footer onClick={onGoToCheckoutClick} totalPrice={totalPrice} />}
  >
    <div style={{ display: 'grid', gap: '24px' }}>
      {cartItems.map((item) => (
        <ShoppingCartMenuItem
          key={item.id}
          item={item}
          onChange={(quantity: number) => onItemChange({ ...item, quantity })}
        />
      ))}
    </div>
  </Sidebar>
)

import { useCallback, useEffect, useState } from 'react'

import type { Restaurant } from '../types'

import { api } from './index'

export const useFetchRestaurants = () => {
  const [status, setStatus] = useState('idle')
  const [restaurants, setRestaurants] = useState<Restaurant[]>([])
  const [retry, setRetry] = useState(false)

  const retryRequest = useCallback(() => {
    setRetry((prev) => !prev)
  }, [setRetry])

  useEffect(() => {
    setStatus('loading')

    api
      .getRestaurants()
      .then((res) => {
        setStatus('success')
        setRestaurants(res)
      })
      .catch((error) => {
        const statusCode = error?.response?.status || 500
        setStatus(statusCode.toString())
      })
  }, [retry])

  return {
    status,
    restaurants,
    retryRequest,
  }
}

export const useFetchRestaurantsByCategory = (categoryId?: string) => {
  const [status, setStatus] = useState('idle')
  const [restaurants, setRestaurants] = useState<Restaurant[]>([])
  const [retry, setRetry] = useState(false)

  const retryRequest = useCallback(() => {
    setRetry((prev) => !prev)
  }, [setRetry])

  useEffect(() => {
    if (categoryId) {
      setStatus('loading')

      api
        .getRestaurantsByCategory(categoryId)
        .then((res) => {
          setStatus('success')
          setRestaurants(res)
        })
        .catch((error) => {
          const statusCode = error?.response?.status || 500
          setStatus(statusCode.toString())
        })
    }
  }, [categoryId, retry])

  return {
    status,
    restaurants,
    retryRequest,
  }
}

export const useFetchRestaurant = (id: string) => {
  const [status, setStatus] = useState('idle')
  const [restaurant, setRestaurant] = useState<Restaurant>()
  const [retry, setRetry] = useState(false)

  const retryRequest = useCallback(() => {
    setRetry((prev) => !prev)
  }, [setRetry])

  useEffect(() => {
    setStatus('loading')

    api
      .getRestaurantById(id)
      .then((res) => {
        setStatus('success')
        setRestaurant(res)
      })
      .catch((error) => {
        const statusCode = error?.response?.status || 500
        setStatus(statusCode.toString())
      })
  }, [id, retry])

  return {
    status,
    restaurant,
    retryRequest,
  }
}

